import React, {useState} from "react";
import "./tickettypenormalCSS.css";

const TicketTypeNormal = () => {


    return(
        <div className="choosetype">
            <table className="table">
                <thead>
                    <tr>
                        <th nowrap="">票種</th>
                        <th nowrap="">價格</th>
                        <th nowrap="">數量</th>
                        <th nowrap="">合計</th>
                    </tr>
                </thead>
                
            </table>
        </div>
    );
};
export default TicketTypeNormal;
